### Backend (Node.js + Express.js + MongoDB)

First, let's set up the server using Express.js and connect it to MongoDB.

#### 1. Initialize the project

```bash
mkdir room-management-system
cd room-management-system
npm init -y
```

#### 2. Install dependencies

```bash
npm install express mongoose body-parser cors
npm install --save-dev nodemon
```

#### 3. Create `server.js`

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();

// Middleware
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/room-management', {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Define Room Schema
const RoomSchema = new mongoose.Schema({
    name: String,
    capacity: Number,
    booked: Boolean
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.json(rooms);
});

app.post('/rooms', async (req, res) => {
    const { name, capacity } = req.body;
    const room = new Room({ name, capacity, booked: false });
    await room.save();
    res.status(201).json(room);
});

app.put('/rooms/:id', async (req, res) => {
    const { id } = req.params;
    const { name, capacity, booked } = req.body;
    const updatedRoom = await Room.findByIdAndUpdate(id, { name, capacity, booked }, { new: true });
    res.json(updatedRoom);
});

app.delete('/rooms/:id', async (req, res) => {
    const { id } = req.params;
    await Room.findByIdAndDelete(id);
    res.status(204).send();
});

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

#### 4. Run the server

```bash
npx nodemon server.js
```

