import base64
from cryptography.fernet import Fernet
from django.conf import settings
from django.utils.module_loading import import_string

class MasterKeyManager:
    @staticmethod
    def get_master_key():
        return settings.MASTER_KEY

    @staticmethod
    def encrypt_data(data):
        master_key = MasterKeyManager.get_master_key()
        fernet = Fernet(base64.urlsafe_b64encode(master_key))
        encrypted_data = fernet.encrypt(data)
        return encrypted_data

    @staticmethod
    def decrypt_data(encrypted_data):
        master_key = MasterKeyManager.get_master_key()
        fernet = Fernet(base64.urlsafe_b64encode(master_key))
        decrypted_data = fernet.decrypt(encrypted_data)
        return decrypted_data


class EncryptionManager:
    @staticmethod
    def encrypt(input_bytes, provider_name='fernet'):
        provider_class = import_string(settings.PROVIDER_REGISTRY[provider_name])
        provider = provider_class()
        return provider.encrypt(input_bytes)

    @staticmethod
    def decrypt(encrypted_bytes, provider_name='fernet'):
        provider_class = import_string(settings.PROVIDER_REGISTRY[provider_name])
        provider = provider_class()
        return provider.decrypt(encrypted_bytes)


